      "\u001b[36mFile \u001b[39m\u001b[32mc:\\Users\\yesiz\\miniconda3\\envs\\ia_nano\\Lib\\site-packages\\crewai\\llm.py:423\u001b[39m, in \u001b[36mLLM.__new__\u001b[39m\u001b[34m(cls, model, is_litellm, **kwargs)\u001b[39m\n\u001b[32m    421\u001b[39m \u001b[38;5;28;01mif\u001b[39;00m \u001b[38;5;129;01mnot\u001b[39;00m LITELLM_AVAILABLE:\n\u001b[32m    422\u001b[39m     logger.error(\u001b[33m\"\u001b[39m\u001b[33mLiteLLM is not available, falling back to LiteLLM\u001b[39m\u001b[33m\"\u001b[39m)\n\u001b[32m--> \u001b[39m\u001b[32m423\u001b[39m     \u001b[38;5;28;01mraise\u001b[39;00m \u001b[38;5;167;01mImportError\u001b[39;00m(\u001b[33m\"\u001b[39m\u001b[33mFallback to LiteLLM is not available\u001b[39m\u001b[33m\"\u001b[39m) \u001b[38;5;28;01mfrom\u001b[39;00m\u001b[38;5;250m \u001b[39m\u001b[38;5;28;01mNone\u001b[39;00m\n\u001b[32m    425\u001b[39m instance = \u001b[38;5;28mobject\u001b[39m.\u001b[34m__new__\u001b[39m(\u001b[38;5;28mcls\u001b[39m)\n\u001b[32m    426\u001b[39m \u001b[38;5;28msuper\u001b[39m(LLM, instance).\u001b[34m__init__\u001b[39m(model=model, is_litellm=\u001b[38;5;28;01mTrue\u001b[39;00m, **kwargs)\n",
