    "# ============================================================\n",
    "# 1. API de Búsqueda: GitHub Repository Search API\n",
    "# ============================================================\n",
    "from langchain_core.tools import tool\n",
    "import httpx, os\n",
    "from crewai import Agent, Task, Crew, Process\n",
    "from external_skills.apis.token_budget_guard import BudgetGuard\n",
    "\n",
    "@tool\n",
    "def search_github_repos(query: str, max_results: int = 5) -> list[dict]:\n",
    "    \"\"\"Busca repositorios en GitHub dado un query de búsqueda.\n",
    "    Retorna una lista de diccionarios con title, abstract y url.\n",
    "    \"\"\"\n",
    "    url = \"https://api.github.com/search/repositories\"\n",
    "    params = {\"q\": query, \"per_page\": max_results}\n",
    "    try:\n",
    "        response = httpx.get(url, params=params, headers={\"User-Agent\": \"Antigravity-IA-Agent\"}, timeout=15)\n",
    "        response.raise_for_status()\n",
    "        data = response.json()\n",
    "        results = []\n",
    "        for item in data.get(\"items\", []):\n",
    "            results.append({\n",
    "                \"title\": item.get(\"full_name\"),\n",
    "                \"abstract\": item.get(\"description\") or \"Sin descripción disponible.\",\n",
    "                \"url\": item.get(\"html_url\")\n",
    "            })\n",
    "        return results\n",
    "    except Exception as e:\n",
    "        return [{\"error\": str(e), \"title\": \"Error\", \"abstract\": \"\", \"url\": \"\"}]\n",
    "\n",
    "# ============================================================\n",
    "# 2. Criterios de Revisión: REPORT_CRITERIA para Software\n",
    "# ============================================================\n",
    "REPORT_CRITERIA = [\n",
    "    {\n",
    "        \"name\": \"tech_accuracy\",\n",
    "        \"description\": \"El reporte describe con precisión técnica las tecnologías, lenguajes y arquitectura del repositorio\",\n",
    "        \"weight\": 0.40,\n",
    "        \"passing_threshold\": 70,\n",
    "    },\n",
    "    {\n",
    "        \"name\": \"documentation_quality\",\n",
    "        \"description\": \"El reporte evalúa la estructura de documentación, legibilidad del README y facilidad de instalación\",\n",
    "        \"weight\": 0.30,\n",
    "        \"passing_threshold\": 60,\n",
    "    },\n",
    "    {\n",
    "        \"name\": \"actionability\",\n",
    "        \"description\": \"Recomendaciones claras y accionables sobre refactorización, dependencias o mejoras de código\",\n",
    "        \"weight\": 0.20,\n",
    "        \"passing_threshold\": 50,\n",
    "    },\n",
    "    {\n",
    "        \"name\": \"brevity\",\n",
    "        \"description\": \"Conciso y estructurado, entre 400 y 800 palabras\",\n",
    "        \"weight\": 0.10,\n",
    "        \"passing_threshold\": 50,\n",
    "    },\n",
    "]\n",
    "\n",
    "# ============================================================\n",
    "# 3. El Modelo del Escritor y Token Budget Guard\n",
    "# ============================================================\n",
    "# Usamos BudgetGuard para monitorear costos usando el modelo premium gemini-2.5-pro\n",
    "writer_budget = BudgetGuard(budget_usd=2.00, model=\"gemini-2.5-pro\")\n",
    "print(f\"Presupuesto asignado para el escritor con Gemini 2.5 Pro: ${writer_budget.budget_usd:.2f} USD\")\n",
    "\n",
    "if os.environ.get(\"OPENROUTER_API_KEY\"):\n",
    "    crew_llm = \"openrouter/google/gemini-2.5-pro\"\n",
    "elif os.environ.get(\"GOOGLE_API_KEY\"):\n",
    "    crew_llm = \"gemini/gemini-2.5-pro\"\n",
    "else:\n",
    "    crew_llm = \"gemini/gemini-2.5-pro\"\n",
    "\n",
    "print(f\"Configurando writer_agent con el modelo: {crew_llm}\")\n",
    "\n",
    "# ============================================================\n",
    "# 4. Destino de Publicación: Endpoint Real de GitHub Issues\n",
    "# ============================================================\n",
    "def publish_agent_node_custom(state: dict) -> dict:\n",
    "    \"\"\"Nodo LangGraph: publica el reporte final como un Issue real de GitHub u otro webhook.\"\"\"\n",
    "    report = state.get(\"final_report\") or state.get(\"draft_report\", \"Sin reporte\")\n",
    "    github_token = os.environ.get(\"GITHUB_TOKEN\")\n",
    "    repo_name = os.environ.get(\"GITHUB_REPOSITORY\", \"user/repo-demo\")\n",
    "    \n",
    "    if github_token:\n",
    "        url = f\"https://api.github.com/repos/{repo_name}/issues\"\n",
    "        headers = {\n",
    "            \"Authorization\": f\"token {github_token}\",\n",
    "            \"Accept\": \"application/vnd.github.v3+json\",\n",
    "            \"User-Agent\": \"Antigravity-IA-Agent\"\n",
    "        }\n",
    "        payload = {\n",
    "            \"title\": f\"Reporte de Arquitectura: {state.get('topic', 'Sin Tema')}\",\n",
    "            \"body\": report\n",
    "        }\n",
    "        try:\n",
    "            res = httpx.post(url, json=payload, headers=headers, timeout=15)\n",
    "            res.raise_for_status()\n",
    "            issue_url = res.json().get(\"html_url\")\n",
    "            print(f\"  [GitHub] Publicado issue exitosamente en: {issue_url}\")\n",
    "            return {\"status\": \"completed\", \"github_issue_url\": issue_url}\n",
    "        except Exception as e:\n",
    "            print(f\"  [GitHub] Error al publicar issue: {e}. Guardando copia local.\")\n",
    "            \n",
    "    # Guardar reporte localmente como fallback\n",
    "    import tempfile\n",
    "    from pathlib import Path\n",
